UPDATE record_templates
SET description = '适用于常规 PCR、菌落 PCR 和扩增条件优化，覆盖样本、引物、反应体系、循环参数、对照与电泳判读',
    updated_at = CURRENT_TIMESTAMP,
    version = 2
WHERE id = '10000000-0000-0000-0000-000000000001';

UPDATE record_templates
SET description = '适用于 SYBR Green qPCR 相对定量实验，覆盖核酸质控、靶基因与内参、重复设计、Ct 数据和熔解曲线',
    updated_at = CURRENT_TIMESTAMP,
    version = 2
WHERE id = '10000000-0000-0000-0000-000000000002';

UPDATE record_templates
SET description = '适用于贴壁细胞复苏、传代、换液、铺板和冻存，覆盖培养条件、汇合度、形态、活率与污染检查',
    updated_at = CURRENT_TIMESTAMP,
    version = 2
WHERE id = '10000000-0000-0000-0000-000000000003';

